from fastapi import FastAPI, UploadFile, File, HTTPException, Header, Request
from fastapi.responses import JSONResponse
from pydantic import BaseModel
from typing import Any, Dict, Optional
import os
import io
import uuid
import pickle
import asyncio

app = FastAPI(title="Multi-tenant Model Serving API", version="1.0.0")

BASE_DIR = os.environ.get("MODEL_STORE_DIR", "./model_store")
os.makedirs(BASE_DIR, exist_ok=True)

_model_locks: Dict[str, asyncio.Lock] = {}
_models: Dict[str, Any] = {}

def _tenant_dir(tenant_id: str) -> str:
    if not tenant_id or "/" in tenant_id or ".." in tenant_id:
        raise HTTPException(status_code=400, detail="Invalid tenant id")
    path = os.path.join(BASE_DIR, tenant_id)
    os.makedirs(path, exist_ok=True)
    return path

def _get_lock(key: str) -> asyncio.Lock:
    lock = _model_locks.get(key)
    if lock is None:
        lock = asyncio.Lock()
        _model_locks[key] = lock
    return lock

def _model_key(tenant_id: str, model_id: str) -> str:
    return f"{tenant_id}:{model_id}"

class InferenceRequest(BaseModel):
    inputs: Any = None
    data: Any = None
    X: Any = None
    kwargs: Optional[Dict[str, Any]] = None

def _call_predict(model: Any, payload: InferenceRequest) -> Any:
    kwargs = payload.kwargs or {}
    if hasattr(model, "predict"):
        if payload.inputs is not None:
            return model.predict(payload.inputs, **kwargs)
        if payload.data is not None:
            return model.predict(payload.data, **kwargs)
        if payload.X is not None:
            return model.predict(payload.X, **kwargs)
        raise HTTPException(status_code=400, detail="No inputs provided (inputs/data/X)")
    if callable(model):
        if payload.inputs is not None:
            return model(payload.inputs, **kwargs)
        if payload.data is not None:
            return model(payload.data, **kwargs)
        if payload.X is not None:
            return model(payload.X, **kwargs)
        raise HTTPException(status_code=400, detail="No inputs provided (inputs/data/X)")
    raise HTTPException(status_code=400, detail="Model is not callable and has no predict()")

@app.exception_handler(Exception)
async def unhandled_exception_handler(request: Request, exc: Exception):
    return JSONResponse(status_code=500, content={"error": "internal_error", "detail": str(exc)})

@app.get("/health")
async def health():
    return {"status": "ok"}

@app.post("/v1/models/upload")
async def upload_model(
    file: UploadFile = File(...),
    x_tenant_id: str = Header(..., alias="X-Tenant-Id"),
    x_model_id: Optional[str] = Header(None, alias="X-Model-Id"),
):
    tenant_id = x_tenant_id.strip()
    model_id = (x_model_id.strip() if x_model_id else str(uuid.uuid4()))
    tdir = _tenant_dir(tenant_id)
    model_path = os.path.join(tdir, f"{model_id}.pkl")

    if file.filename and not file.filename.lower().endswith((".pkl", ".pickle")):
        raise HTTPException(status_code=400, detail="Only .pkl/.pickle files are accepted")

    raw = await file.read()
    if not raw:
        raise HTTPException(status_code=400, detail="Empty file")

    tmp_path = model_path + ".tmp"
    with open(tmp_path, "wb") as f:
        f.write(raw)
    os.replace(tmp_path, model_path)

    key = _model_key(tenant_id, model_id)
    lock = _get_lock(key)
    async with lock:
        try:
            model = pickle.load(io.BytesIO(raw))
        except Exception as e:
            try:
                os.remove(model_path)
            except Exception:
                pass
            raise HTTPException(status_code=400, detail=f"Failed to load model: {e}")
        _models[key] = model

    return {"tenant_id": tenant_id, "model_id": model_id, "stored_as": model_path}

@app.post("/v1/models/{model_id}/load")
async def load_model(
    model_id: str,
    x_tenant_id: str = Header(..., alias="X-Tenant-Id"),
):
    tenant_id = x_tenant_id.strip()
    tdir = _tenant_dir(tenant_id)
    model_path = os.path.join(tdir, f"{model_id}.pkl")
    if not os.path.exists(model_path):
        raise HTTPException(status_code=404, detail="Model file not found")

    key = _model_key(tenant_id, model_id)
    lock = _get_lock(key)
    async with lock:
        try:
            with open(model_path, "rb") as f:
                model = pickle.load(f)
        except Exception as e:
            raise HTTPException(status_code=400, detail=f"Failed to load model: {e}")
        _models[key] = model

    return {"tenant_id": tenant_id, "model_id": model_id, "loaded": True}

@app.delete("/v1/models/{model_id}")
async def unload_model(
    model_id: str,
    x_tenant_id: str = Header(..., alias="X-Tenant-Id"),
    delete_file: bool = False,
):
    tenant_id = x_tenant_id.strip()
    key = _model_key(tenant_id, model_id)
    _models.pop(key, None)

    if delete_file:
        tdir = _tenant_dir(tenant_id)
        model_path = os.path.join(tdir, f"{model_id}.pkl")
        try:
            os.remove(model_path)
        except FileNotFoundError:
            pass

    return {"tenant_id": tenant_id, "model_id": model_id, "unloaded": True, "deleted_file": bool(delete_file)}

@app.post("/v1/models/{model_id}/predict")
async def predict(
    model_id: str,
    payload: InferenceRequest,
    x_tenant_id: str = Header(..., alias="X-Tenant-Id"),
    autoload: bool = True,
):
    tenant_id = x_tenant_id.strip()
    key = _model_key(tenant_id, model_id)
    lock = _get_lock(key)

    async with lock:
        model = _models.get(key)
        if model is None and autoload:
            tdir = _tenant_dir(tenant_id)
            model_path = os.path.join(tdir, f"{model_id}.pkl")
            if not os.path.exists(model_path):
                raise HTTPException(status_code=404, detail="Model not found")
            try:
                with open(model_path, "rb") as f:
                    model = pickle.load(f)
            except Exception as e:
                raise HTTPException(status_code=400, detail=f"Failed to load model: {e}")
            _models[key] = model
        elif model is None:
            raise HTTPException(status_code=404, detail="Model not loaded")

    try:
        result = _call_predict(model, payload)
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Inference failed: {e}")

    return {"tenant_id": tenant_id, "model_id": model_id, "result": result}

@app.get("/v1/models")
async def list_models(
    x_tenant_id: str = Header(..., alias="X-Tenant-Id"),
    include_loaded: bool = True,
):
    tenant_id = x_tenant_id.strip()
    tdir = _tenant_dir(tenant_id)
    files = []
    for name in os.listdir(tdir):
        if name.endswith(".pkl"):
            files.append(name[:-4])
    files.sort()

    loaded = []
    if include_loaded:
        prefix = f"{tenant_id}:"
        loaded = sorted([k.split(":", 1)[1] for k in _models.keys() if k.startswith(prefix)])

    return {"tenant_id": tenant_id, "stored_model_ids": files, "loaded_model_ids": loaded}